import jetbrains.mps.baselanguage.unitTest.execution.launcher.TestsContributor;
import org.junit.runners.model.RunnerBuilder;
import org.junit.internal.builders.AllDefaultPossibilitiesBuilder;
import java.util.ArrayList;
import org.junit.runner.Request;
import jetbrains.mps.baselanguage.unitTest.execution.launcher.ExecutorScript;
import org.junit.runner.Description;

public class JUnit4TestExecutor extends AbstractJUnitTestMixin {
  private static final Logger LOG = Logger.getLogger(JUnit4TestExecutor.class);
  private final TestsContributor myTestsContributor;
  private RunnerBuilder myRunnerBuilder;

  public JUnit4TestExecutor(TestsContributor testsContributor, boolean redirectStdOutErr) {
    super(redirectStdOutErr);
    myTestsContributor = testsContributor;
  }

  @Override
  protected void executeSafe() throws Throwable {
    if (myTestsContributor.newAPI()) {
      myRunnerBuilder = new AllDefaultPossibilitiesBuilder(true);
      ArrayList<Request> tests = new ArrayList<>();
      for (ExecutorScript.TestRecord tr : myTestsContributor.tests()) {
        final ClassLoader classLoader = myTestsContributor.classLoader(tr);
        for (int i = 0, x = tr.myTestQualifiedName.size(); i < x; i++) {
          String qualifiedName = tr.myTestQualifiedName.get(i);
          boolean isTestCase = Boolean.valueOf(tr.isTestCase.get(i)).booleanValue();
          Request r = (isTestCase ? processTestClass(classLoader, qualifiedName) : processTestMethod(classLoader, qualifiedName));
          if (r != null) {
            tests.add(r);
          }
        }
      }
      myRunnerBuilder = null;
      executeWithJunit4(tests);
    } else {
      executeWithJunit4(myTestsContributor.gatherTests());
    }
  }

  private Request processTestClass(ClassLoader cl, String fqName) {
    Class<?> testClass = getTestClass(cl, fqName);
    return (testClass != null ? Request.runner(myRunnerBuilder.safeRunnerForClass(testClass)) : null);
  }

  private Request processTestMethod(ClassLoader cl, String fqName) {
    int index = fqName.lastIndexOf('.');
    String testClassName = fqName.substring(0, index);
    String testMethod = fqName.substring(index + 1);
    Request classReq = processTestClass(cl, testClassName);
    // Copied from Request.method(Class<?>, String); all we care is uniqueId (built from class and methods names), so don't care about Class<> instance
    return (classReq != null ? classReq.filterWith(Description.createTestDescription(testClassName, testMethod)) : null);
  }

  private static Class<?> getTestClass(ClassLoader cl, String className) {
    Class<?> testClass = null;
    try {
      testClass = cl.loadClass(className);
    } catch (ClassNotFoundException e) {
      if (LOG.isErrorLevel()) {
        LOG.error("Test class " + className + " has not been found: it will be skipped", e);
      }
    }
    return testClass;
  }

}
